    23	                    // check if any scope in a chain is a non-arrow function
    24	                    && ctx.ancestor_scopes().any(|scope| {
    25	                        let scope_flags = ctx.scoping().scope_flags(scope);
    26	                        scope_flags.is_function() && !scope_flags.is_arrow()
    27	                    })
    28	            }
