   136	    /// Remove unused specifiers from import declarations.
   137	    ///
   138	    /// Since we don't know if an import has side effects, we convert imports
   139	    /// with all unused specifiers to side-effect-only imports (`import 'x'`)
   140	    /// rather than removing them entirely.
   141	    ///
   142	    /// ## Example
   143	    ///
   144	    /// Input:
   145	    /// ```js
   146	    /// import a from 'a'
   147	    /// import { b } from 'b'
   148	    ///
   149	    /// if (false) {
   150	    ///   console.log(b)
   151	    /// }
   152	    /// ```
   153	    ///
   154	    /// Output:
   155	    /// ```js
   156	    /// import 'a'
   157	    /// import 'b'
   158	    /// ```
   159	    pub fn remove_unused_import_specifiers(stmt: &mut Statement<'a>, ctx: &mut TraverseCtx<'a>) {
   160	        if ctx.options().treeshake.invalid_import_side_effects
   161	            || ctx.state.options.unused == CompressOptionsUnused::Keep
   162	        {
   163	            return;
   164	        }
   165	
   166	        if ctx.scoping().root_scope_flags().contains_direct_eval() {
   167	            return;
   168	        }
   169	
   170	        debug_assert!(!ctx.source_type().is_script(), "imports are not allowed in script mode");
   171	
   172	        let Statement::ImportDeclaration(import_decl) = stmt else { return };
   173	
   174	        if let Some(phase) = import_decl.phase {
   175	            let (ImportPhase::Defer | ImportPhase::Source) = phase;
   176	            if ctx.scoping().symbol_is_unused(
   177	                import_decl.specifiers.as_ref().unwrap().first().unwrap().local().symbol_id(),
   178	            ) {
   179	                *stmt = ctx.ast.statement_empty(import_decl.span);
   180	                ctx.state.changed = true;
   181	            }
   182	
   183	            return;
   184	        }
   185	
   186	        let Some(specifiers) = &mut import_decl.specifiers else {
   187	            return;
   188	        };
   189	
   190	        let original_len = specifiers.len();
   191	
   192	        specifiers.retain(|specifier| {
   193	            let local = match specifier {
   194	                ImportDeclarationSpecifier::ImportSpecifier(s) => &s.local,
   195	                ImportDeclarationSpecifier::ImportDefaultSpecifier(s) => &s.local,
   196	                ImportDeclarationSpecifier::ImportNamespaceSpecifier(s) => &s.local,
   197	            };
   198	
   199	            let symbol_id = local.symbol_id();
   200	            !ctx.scoping().symbol_is_unused(symbol_id)
   201	        });
   202	
   203	        if specifiers.len() != original_len {
   204	            ctx.state.changed = true;
   205	        }
   206	
   207	        if specifiers.is_empty() {
   208	            import_decl.specifiers = None;
   209	            ctx.state.changed = true;
   210	        }
   211	    }
