   648	    /// Try to remove a member expression assignment (e.g. `A.from = () => {}`).
   649	    /// Checks side-effect analysis (respects `property_write_side_effects`) and
   650	    /// verifies the root object is an unused local binding.
   651	    fn remove_unused_member_assignment(e: &Expression<'a>, ctx: &mut TraverseCtx<'a>) -> bool {
   652	        if Self::keep_top_level_var_in_script_mode(ctx) {
   653	            return false;
   654	        }
   655	        let Expression::AssignmentExpression(assign_expr) = e else { unreachable!() };
   656	
   657	        // Track `__proto__` and computed member writes before checking side effects.
   658	        // Even if this expression has side effects and can't be removed, we need to
   659	        // record proto writes so that subsequent property writes on the same symbol
   660	        // are preserved (the `__proto__` assignment may install setters).
   661	        Self::track_proto_write(assign_expr, ctx);
   662	
   663	        if e.may_have_side_effects(ctx) {
   664	            return false;
   665	        }
   666	        Self::is_member_assign_to_unused_binding(assign_expr, ctx)
