   668	
   669	    /// Track `__proto__` and computed member writes on local bindings.
   670	    /// Must be called before side-effect checks so that proto writes with
   671	    /// side-effectful RHS still mark the symbol.
   672	    fn track_proto_write(assign_expr: &AssignmentExpression<'a>, ctx: &mut TraverseCtx<'a>) {
   673	        // Skip when property_write_side_effects is true (default) — the optimization
   674	        // that drops member writes is disabled, so tracking is unnecessary.
   675	        if ctx.state.options.treeshake.property_write_side_effects {
   676	            return;
   677	        }
   678	        // Match only potential `__proto__` writes: explicit `a.__proto__` or
   679	        // computed `a[b]` (where the key could evaluate to `"__proto__"`).
   680	        let object = match &assign_expr.left {
   681	            AssignmentTarget::StaticMemberExpression(e) if e.property.name == "__proto__" => {
   682	                &e.object
   683	            }
   684	            // Computed key like `a[b]` could be `"__proto__"`
   685	            AssignmentTarget::ComputedMemberExpression(e) => &e.object,
   686	            _ => return,
   687	        };
   688	        let Expression::Identifier(ident) = object else { return };
   689	        let reference_id = ident.reference_id();
   690	        let Some(symbol_id) = ctx.scoping().get_reference(reference_id).symbol_id() else {
   691	            return;
   692	        };
   693	        // Only mark if there are other member writes — if __proto__ is the only
   694	        // reference, the setter is installed but never triggered, so dropping is safe.
   695	        let ref_count = ctx.scoping().get_resolved_reference_ids(symbol_id).len();
   696	        if ref_count > 1 {
   697	            ctx.state.proto_write_symbols.insert(symbol_id);
   698	        }
   699	    }
   700	
   701	    /// Resolve the symbol ID of a member assignment's base object identifier.
   702	    /// Returns `None` for chained access (`a.b.c`), non-identifier bases, or
   703	    /// non-member assignment targets.
   704	    fn resolve_member_assign_object_symbol(
   705	        assign_expr: &AssignmentExpression<'a>,
   706	        ctx: &TraverseCtx<'a>,
   707	    ) -> Option<SymbolId> {
   708	        // Only handle single-level member expressions (A.foo, not a.b.c).
   709	        let object = match &assign_expr.left {
   710	            AssignmentTarget::StaticMemberExpression(e) => &e.object,
   711	            AssignmentTarget::ComputedMemberExpression(e) => &e.object,
   712	            AssignmentTarget::PrivateFieldExpression(e) => &e.object,
   713	            _ => return None,
   714	        };
   715	        let Expression::Identifier(ident) = object else { return None };
   716	        ctx.scoping().get_reference(ident.reference_id()).symbol_id()
   717	    }
   718	
   719	    /// Check if a member expression assignment (e.g. `A.from = () => {}`) targets
   720	    /// a local binding whose only references are property-write targets.
   721	    ///
   722	    /// Three conditions must hold:
   723	    /// 1. The target is a single-level member expression (`A.foo`, not `a.b.c`)
   724	    /// 2. ALL references to the symbol are member write targets
   725	    /// 3. The symbol creates a fresh value (not an alias) and is not exported
   726	    /// 4. The symbol has no `__proto__` member writes (which could install setters)
   727	    fn is_member_assign_to_unused_binding(
   728	        assign_expr: &AssignmentExpression<'a>,
   729	        ctx: &TraverseCtx<'a>,
   730	    ) -> bool {
   731	        let Some(symbol_id) = Self::resolve_member_assign_object_symbol(assign_expr, ctx) else {
   732	            return false;
   733	        };
   734	
   735	        // If this symbol has `__proto__` or computed member writes, don't drop any
   736	        // property writes — the `__proto__` assignment may have installed setters.
   737	        if ctx.state.proto_write_symbols.contains(&symbol_id) {
   738	            return false;
   739	        }
   740	
   741	        // Check: symbol creates a fresh value (not an alias) and is not exported.
   742	        let Some(sv) = ctx.state.symbol_values.get_symbol_value(symbol_id) else {
   743	            return false;
   744	        };
   745	        if !sv.is_fresh_value || sv.exported {
   746	            return false;
   747	        }
   748	        // Check: all references are member write targets (O(1) via pre-computed count).
   749	        sv.write_references_count == 0
   750	            && sv.read_references_count == sv.member_write_target_read_count
   751	    }
