   753	    fn remove_unused_class_expr(e: &mut Expression<'a>, ctx: &mut TraverseCtx<'a>) -> bool {
   754	        let Expression::ClassExpression(c) = e else { return false };
   755	        if let Some(exprs) = Self::remove_unused_class(c, ctx) {
   756	            if exprs.is_empty() {
   757	                return true;
   758	            }
   759	            *e = ctx.ast.expression_sequence(c.span, exprs);
   760	        }
   761	        false
   762	    }
   763	
   764	    pub fn remove_unused_class(
   765	        c: &mut Class<'a>,
   766	        ctx: &mut TraverseCtx<'a>,
   767	    ) -> Option<Vec<'a, Expression<'a>>> {
   768	        // TypeError `class C extends (() => {}) {}`
   769	        if c.super_class
   770	            .as_ref()
   771	            .is_some_and(|e| matches!(e, Expression::ArrowFunctionExpression(_)))
   772	        {
   773	            return None;
   774	        }
   775	        // Don't remove classes with decorators - they may have side effects
   776	        if !c.decorators.is_empty() {
   777	            return None;
   778	        }
   779	        // Keep the entire class if there are class level side effects.
   780	        for e in &c.body.body {
   781	            match e {
   782	                e if e.has_decorator() => return None,
   783	                ClassElement::TSIndexSignature(_) => return None,
   784	                ClassElement::StaticBlock(block) if !block.body.is_empty() => return None,
   785	                ClassElement::PropertyDefinition(prop)
   786	                    if prop.r#static
   787	                        && prop.value.as_ref().is_some_and(|v| v.may_have_side_effects(ctx)) =>
   788	                {
   789	                    return None;
   790	                }
   791	                ClassElement::AccessorProperty(prop)
   792	                    if prop.r#static
   793	                        && prop.value.as_ref().is_some_and(|v| v.may_have_side_effects(ctx)) =>
   794	                {
   795	                    return None;
   796	                }
   797	                _ => {}
   798	            }
   799	        }
   800	
   801	        // Otherwise extract the expressions.
   802	        let mut exprs = ctx.ast.vec();
   803	
   804	        if let Some(e) = &mut c.super_class
   805	            && e.may_have_side_effects(ctx)
   806	        {
   807	            exprs.push(c.super_class.take().unwrap());
   808	        }
   809	
   810	        for e in &mut c.body.body {
   811	            // Save computed key.
   812	            if e.computed()
   813	                && let Some(key) = match e {
   814	                    ClassElement::TSIndexSignature(_) | ClassElement::StaticBlock(_) => None,
   815	                    ClassElement::MethodDefinition(def) => Some(&mut def.key),
   816	                    ClassElement::PropertyDefinition(def) => Some(&mut def.key),
   817	                    ClassElement::AccessorProperty(def) => Some(&mut def.key),
   818	                }
   819	                && let Some(expr) = key.as_expression_mut()
   820	                && expr.may_have_side_effects(ctx)
   821	            {
   822	                exprs.push(expr.take_in(ctx.ast));
   823	            }
   824	            // Save static initializer.
   825	            if e.r#static()
   826	                && let Some(init) = match e {
   827	                    ClassElement::TSIndexSignature(_)
   828	                    | ClassElement::StaticBlock(_)
   829	                    | ClassElement::MethodDefinition(_) => None,
   830	                    ClassElement::PropertyDefinition(def) => def.value.take(),
   831	                    ClassElement::AccessorProperty(def) => def.value.take(),
   832	                }
   833	            {
   834	                // Already checked side effects above.
   835	                exprs.push(init);
   836	            }
   837	        }
   838	
   839	        ctx.state.changed = true;
   840	        Some(exprs)

